### FastAPI Endpoints

Here is a broad overview of what your FastAPI endpoints might look like:

```python
from fastapi import FastAPI, HTTPException, File, UploadFile, Form
from typing import List
from models import Document, Tag, Category, DocumentVersion  # Define these in your models.py
from schemas import DocumentSchema, DocumentCreateSchema  # Define these in your schemas.py
from database import SessionLocal  # Define the SQLAlchemy session maker in your database.py

app = FastAPI()

# Dependency to get the database session
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

@app.post("/documents/", response_model=DocumentSchema)
def create_document(document: DocumentCreateSchema, db: Session = Depends(get_db)):
    new_doc = Document(**document.dict())
    db.add(new_doc)
    db.commit()
    return new_doc

@app.get("/documents/", response_model=List[DocumentSchema])
def list_documents(db: Session = Depends(get_db)):
    return db.query(Document).all()

@app.get("/documents/{document_id}", response_model=DocumentSchema)
def get_document(document_id: int, db: Session = Depends(get_db)):
    doc = db.query(Document).get(document_id)
    if doc is None:
        raise HTTPException(status_code=404, detail="Document not found")
    return doc

@app.put("/documents/{document_id}", response_model=DocumentSchema)
def update_document(document_id: int, document: DocumentCreateSchema, db: Session = Depends(get_db)):
    db_doc = db.query(Document).get(document_id)
    if db_doc is None:
        raise HTTPException(status_code=404, detail="Document not found")

    # Here you will update the document and create a new DocumentVersion
    # Update db_doc fields here...

    db.add(db_doc)
    db.commit()
    return db_doc

@app.post("/documents/upload/")
def upload_file(file: UploadFile = File(...), db: Session = Depends(get_db)):
    content = file.file.read()  # Read file content
    # Modify and adjust as needed, e.g., save file in server and save path in DB, instead of content
    new_doc = Document(title=file.filename, content=content)
    db.add(new_doc)
    db.commit()
    return {"filename": file.filename}
```

### Models With Versioning

To implement versioning in your SQLAlchemy models, you would create an additional table to track changes:

```python
class DocumentVersion(Base):
    __tablename__ = 'document_versions'
    id = Column(Integer, primary_key=True)
    document_id = Column(Integer, ForeignKey('documents.id'))
    content = Column(Text)
    created_at = Column(DateTime, default=func.now())

class Document(Base):
    __tablename__ = 'documents'
    id = Column(Integer, primary_key=True)
    # Other columns...
    versions = relationship('DocumentVersion', backref='document')

    def create_version(self, db):
        # Create a new version before updating the document
        version = DocumentVersion(document_id=self.id, content=self.content)
        db.add(version)
        db.commit()
```

