Certainly! To enable Pydantic validation for your FastAPI endpoints, let's create `schemas.py` which will define Pydantic models corresponding to your SQLAlchemy models and for request/response serialization.

```python
# schemas.py
from datetime import datetime
from typing import List, Optional
from pydantic import BaseModel

class TagBase(BaseModel):
    name: str

class TagCreate(TagBase):
    pass

class Tag(TagBase):
    id: int

    class Config:
        orm_mode = True

class CategoryBase(BaseModel):
    name: str

class CategoryCreate(CategoryBase):
    pass

class Category(CategoryBase):
    id: int

    class Config:
        orm_mode = True

class DocumentVersionBase(BaseModel):
    content: str

class DocumentVersionCreate(DocumentVersionBase):
    pass

class DocumentVersion(DocumentVersionBase):
    id: int
    created_at: datetime

    class Config:
        orm_mode = True

class DocumentBase(BaseModel):
    title: str

class DocumentCreate(DocumentBase):
    content: str  # Initial content for the document
    tags: Optional[List[int]] = None
    categories: Optional[List[int]] = None

class Document(DocumentBase):
    id: int
    current_version_id: int
    created_at: datetime
    updated_at: Optional[datetime] = None
    versions: List[DocumentVersion] = []
    tags: List[Tag] = []
    categories: List[Category] = []

    class Config:
        orm_mode = True

# Schemas for responses
class DocumentWithCurrentVersion(Document):
    current_version: DocumentVersion

class DocumentVersionHistory(BaseModel):
    version_id: int
    timestamp: datetime

class DocumentSearchResults(BaseModel):
    documents: List[DocumentWithCurrentVersion]
```

These Pydantic models serve multiple purposes:

- **Schema Validation:** Pydantic models validate incoming data against expected datatypes and structure.
- **ORM Mode:** The `orm_mode = True` setting tells Pydantic to read the data even if it is not a `dict` but an ORM model (like SQLAlchemy). This is useful when you directly fetch database records and return them in your FastAPI endpoints.
- **Complex Structures:** For complex structures that combine documents with versions, tags, and categories, you can create composite models such as `DocumentWithCurrentVersion` which includes nested versions, or `DocumentSearchResults` which encapsulates a list of search result documents.

These models can be directly utilized in your FastAPI endpoint definitions as the `response_model` parameter to serialize the SQLAlchemy models into JSON responses and as function parameters to validate client requests.

Now when you build your FastAPI endpoints, you'll construct request payloads using the appropriate 'Create' models (e.g., `DocumentCreate`) and set the `response_model` to the full models to serialize with all necessary details (e.g., `DocumentWithCurrentVersion` for a document retrieve endpoint).

Remember to test these schemas with different payloads to ensure they validate correctly and that the serialized output is as expected. This will also help in documenting your API as FastAPI uses these schemas to generate OpenAPI specs for auto-generated documentation.

Let's define the endpoints for document management in `document_routes.py`. This will include endpoints for creating a new document, updating a document, retrieving documents by ID, listing all documents, managing document versions, and searching. 

```python
# document_routes.py
from fastapi import APIRouter, HTTPException, Depends, Body, Query
from typing import List
from sqlalchemy.orm import Session
from database import get_db  # Be sure that get_db is defined in your database module
from models import Document as DBDocument
import crud
import schemas

router = APIRouter()

@router.post("/documents/", response_model=schemas.DocumentWithCurrentVersion)
def create_document(document: schemas.DocumentCreate, db: Session = Depends(get_db)):
    new_document = crud.create_document(db=db, title=document.title, content=document.content)
    return new_document

@router.get("/documents/", response_model=List[schemas.Document])
def read_documents(skip: int = Query(default=0), limit: int = Query(default=10), db: Session = Depends(get_db)):
    documents = crud.get_documents(db=db)
    return documents[skip: skip + limit]

@router.get("/documents/{document_id}", response_model=schemas.DocumentWithCurrentVersion)
def read_document(document_id: int, db: Session = Depends(get_db)):
    document = crud.get_document(db=db, document_id=document_id)
    if document is None:
        raise HTTPException(status_code=404, detail="Document not found")
    return document

@router.put("/documents/{document_id}", response_model=schemas.DocumentWithCurrentVersion)
def update_document(
    document_id: int, document_data: schemas.DocumentCreate, db: Session = Depends(get_db)
):
    document = crud.update_document(db=db, document_id=document_id, content=document_data.content)
    if not document:
        raise HTTPException(status_code=404, detail="Document not found")
    return document

@router.get("/documents/{document_id}/versions", response_model=List[schemas.DocumentVersion])
def get_document_versions(document_id: int, db: Session = Depends(get_db)):
    versions = crud.get_document_versions(db=db, document_id=document_id)
    return versions

@router.post("/documents/{document_id}/versions/{version_id}", response_model=schemas.DocumentWithCurrentVersion)
def revert_to_version(document_id: int, version_id: int, db: Session = Depends(get_db)):
    document = crud.revert_document_version(db=db, document_id=document_id, version_id=version_id)
    if not document:
        raise HTTPException(status_code=404, detail="Document not found")
    return document

@router.get("/search/", response_model=List[schemas.DocumentWithCurrentVersion])
def search_docs(query: str, db: Session = Depends(get_db)):
    results = crud.search_documents(db=db, query=query)
    if not results:
        raise HTTPException(status_code=404, detail="No matching documents found")
    return results

# Additional endpoints for handling tags and categories...

# Tag Endpoints
@router.post("/tags/", response_model=schemas.Tag)
def create_tag(tag: schemas.TagCreate, db: Session = Depends(get_db)):
    return crud.create_tag(db=db, tag_name=tag.name)

@router.get("/tags/", response_model=List[schemas.Tag])
def list_tags(db: Session = Depends(get_db)):
    return crud.get_tags(db=db)

@router.put("/documents/{document_id}/tags/{tag_id}")
def assign_tag(document_id: int, tag_id: int, db: Session = Depends(get_db)):
    document = crud.assign_tag_to_document(db=db, document_id=document_id, tag_id=tag_id)
    if not document:
        raise HTTPException(status_code=404, detail="Document not found or tag does not exist")
    return {"message": "Tag assigned"}

# Category Endpoints
@router.post("/categories/", response_model=schemas.Category)
def create_category(category: schemas.CategoryCreate, db: Session = Depends(get_db)):
    return crud.create_category(db=db, category_name=category.name)

@router.get("/categories/", response_model=List[schemas.Category])
def list_categories(db: Session = Depends(get_db)):
    return crud.get_categories(db=db)

@router.put("/documents/{document_id}/categories/{category_id}")
def assign_category(document_id: int, category_id: int, db: Session = Depends(get_db)):
    document = crud.assign_category_to_document(db=db, document_id=document_id, category_id=category_id)
    if not document:
        raise HTTPException(status_code=404, detail="Document not found or category does not exist")
    return {"message": "Category assigned"}

# Make sure to include this router in your main FastAPI app.
```

Make sure to include this router in your main FastAPI app by using:

```python
